#!/usr/bin/env python3
"""Validate schema-level sanity of result.pkl generated by tools/test.py."""

import argparse
import pickle
import sys
from typing import Any


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("--result-pkl", required=True, help="Path to result.pkl")
    parser.add_argument("--expected-count", type=int, default=None, help="Expected annotation count")
    return parser.parse_args()


def _describe_value(name: str, value: Any) -> str:
    shape = getattr(value, "shape", None)
    dtype = getattr(value, "dtype", None)
    if shape is not None:
        return f"{name}: type={type(value).__name__}, shape={tuple(shape)}, dtype={dtype}"
    if isinstance(value, (list, tuple)):
        return f"{name}: type={type(value).__name__}, len={len(value)}"
    return f"{name}: type={type(value).__name__}, value={value!r}"


def main() -> int:
    args = parse_args()

    with open(args.result_pkl, "rb") as f:
        result = pickle.load(f)

    if not isinstance(result, list):
        print(f"ERROR: expected list in result.pkl, got {type(result).__name__}", file=sys.stderr)
        return 2

    count = len(result)
    print(f"result_pkl: {args.result_pkl}")
    print(f"num_annotations: {count}")

    if args.expected_count is not None and count != args.expected_count:
        print(
            f"ERROR: expected_count={args.expected_count}, actual_count={count}",
            file=sys.stderr,
        )
        return 1

    if count == 0:
        print("WARNING: result list is empty")
        return 0

    first = result[0]
    if not isinstance(first, dict):
        print(f"ERROR: expected first annotation dict, got {type(first).__name__}", file=sys.stderr)
        return 2

    keys = sorted(first.keys())
    print(f"first_annotation_keys: {keys}")

    for key in ["name", "score", "boxes_lidar", "dimensions", "location", "rotation_y", "bbox"]:
        if key in first:
            print(_describe_value(key, first[key]))
        else:
            print(f"{key}: <missing>")

    return 0


if __name__ == "__main__":
    raise SystemExit(main())
